        doiPlotLegend = doiPlotLegend,
        doiPlotLegendPos = doiPlotLegendPos,
        doiPlotLegendCex = doiPlotLegendCex,
        lfkIndex = lfkIndex)

    analysis <- metaContClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

